import type { SyntaxNodeRef } from '@lezer/common';

import type { ConvertedLezerNode } from '../../../../types/conversion-utils.js';
import type { FilterFieldDurationNode } from '../../../../types/tree-nodes.js';
import { getTextFromRange } from '../../../get-text.js';

/**
 * Convert a duration node.
 * @internal
 */
export function convertDuration(
  node: SyntaxNodeRef,
  doc: string,
): ConvertedLezerNode<FilterFieldDurationNode> {
  const { from, to } = node;
  const textValue = getTextFromRange(node, doc);
  const count = parseInt(textValue);

  const convertedNode: FilterFieldDurationNode = {
    type: 'Duration',
    textValue,
    value: count,
    unit: textValue.replace(`${count}`, '') as FilterFieldDurationNode['unit'],
    range: { from, to },
  };

  return { convertedNode, errors: [] };
}
